PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE runs (
    run_id       INTEGER PRIMARY KEY AUTOINCREMENT,
    started_utc  TEXT NOT NULL,
    finished_utc TEXT,
    status       TEXT NOT NULL DEFAULT 'running',
    llm_model    TEXT,
    code_version TEXT,
    notes        TEXT
);
CREATE TABLE decisions (
    id           INTEGER PRIMARY KEY AUTOINCREMENT,
    run_id       INTEGER NOT NULL REFERENCES runs(run_id),
    arm          TEXT NOT NULL,
    ticker       TEXT NOT NULL,
    signal       TEXT NOT NULL,             -- BUY / HOLD / SELL
    price        REAL,                      -- price at decision time
    rationale    TEXT,                      -- human-readable reasoning
    inputs_json  TEXT,                      -- full data packet the arm saw
    raw_response TEXT,                      -- LLM only: verbatim model output
    latency_ms   INTEGER,
    error        TEXT,                      -- non-null if the arm failed
    created_utc  TEXT NOT NULL
);
CREATE TABLE trades (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    run_id      INTEGER NOT NULL REFERENCES runs(run_id),
    arm         TEXT NOT NULL,
    ticker      TEXT NOT NULL,
    side        TEXT NOT NULL,              -- BUY / SELL
    qty         REAL NOT NULL,
    price       REAL NOT NULL,
    notional    REAL NOT NULL,
    created_utc TEXT NOT NULL
);
CREATE TABLE positions (
    arm      TEXT NOT NULL,
    ticker   TEXT NOT NULL,
    qty      REAL NOT NULL,
    avg_cost REAL NOT NULL,
    PRIMARY KEY (arm, ticker)
);
CREATE TABLE arms (
    arm  TEXT PRIMARY KEY,
    cash REAL NOT NULL
);
CREATE TABLE snapshots (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    run_id      INTEGER NOT NULL REFERENCES runs(run_id),
    arm         TEXT NOT NULL,
    cash        REAL NOT NULL,
    equity      REAL NOT NULL,
    created_utc TEXT NOT NULL
);
CREATE INDEX idx_decisions_arm_ticker ON decisions(arm, ticker);
CREATE INDEX idx_snapshots_arm ON snapshots(arm);
COMMIT;
